public display PurchPrice  ETGGRNRate()
{
    if(this.Qty !=0 )
    {
        return  round(this.ValueMST / this.Qty ,0.01);
    }
    else
    {
        return 0;
    }
}

public display PurchPrice  ETGBinQtySelectedRate()
{
    if(this.Qty !=0 )
    {
        return  round(this.ValueMST / this.Qty ,0.01) * this.ETGQtyRequired;
    }
    else
    {
        return 0;
    }
}
